sp_widget.client_script:
function($scope, $rootScope, amb, spUtil) {  
//------------------------------------------------------------------------------------------------------------------------
// WIDGET BASE: FIELDS
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES
//------------------------------------------------------------------------------------------------------------------------

	/* widget controller */  

	var c = this;
	// DFCT0010343 - TUP - Filter was not working for OU Templates in Template LIst screen - issue introduced in 2.6
	var watcher;
	initRecordWatcher(c.data.table, c.data.filter);
	function initRecordWatcher(table, filter) {
		if (watcher)
			watcher.unsubscribe();

		if (table && filter) {
			// STRY0093948 - when a row is removed, broadcast event to Tab Form with Tabs to update the count
			var params = {};
			var watcherChannel = amb.getChannelRW(table, filter);
			amb.connect();
			watcher = watcherChannel.subscribe(function(name) {
				$scope.server.update();
			});
		}
	}

	// spUtil.recordWatch($scope, c.data.table, c.data.filter);				 
	var onListClick = $scope.$on('$sp.list.click', function(e, parms) {
		refreshWidget(parms);
	});
	// DFCT0010343 - TUP - Filter was not working for OU Templates in Template LIst screen - issue introduced in 2.6
	// var onSaveUpdate = $scope.$on('sp.form.record.updated', refreshWidget);

	// STRY0097809
	var onTaskDrillDown = $scope.$on('$taskerTabbedForm.drillDownList.click', function(e, parms) {
		refreshWidget(parms);
	});
	var onTaskTasklListClick = $scope.$on('$TaskerTaskList.click', function(e, parms) {
		refreshWidget(parms);
	});

	function refreshWidget(parms) {
		c.data.table = parms.table;
		c.data.sys_id = parms.sys_id;
		$scope.server.update().then(function(){
			// DFCT0010343 - TUP - Filter was not working for OU Templates in Template LIst screen - issue introduced in 2.6
			initRecordWatcher(c.data.table, c.data.filter);
		});
	}
}

sp_widget.css:
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES 
// RECURSIVE LIST TREE
//------------------------------------------------------------------------------------------------------------------------
//------------------------------------------------------------------------------------------------------------------------
// 2.5.21 | 09.01.2020 | KT | UI  | STRY0074067: TECH - Tasker - Unified CSS on widgets (Internal Story, PO story needed)
//------------------------------------------------------------------------------------------------------------------------

.taskertype{
  display:inline-block;
  border-bottom:2px solid #004475;
  padding-bottom:3px;
  float: right;
  font-size: 13px;
  padding-top: 15px;
  margin-right: 10px;
}

.btn {
  margin-bottom: 10px;
  /* make chevron non-clickable and do not change the cursor on hover */
  pointer-events: none;
}

.btn-arrow-right,
.btn-arrow-left {
  position: relative;
}

.btn-arrow-right {
  padding-left: 17px;
}

.btn-arrow-left {
  padding-right: 17px;
}

.btn-arrow-right:before,
.btn-arrow-right:after,
.btn-arrow-left:before,
.btn-arrow-left:after { /* make two squares (before and after), looking similar to the button */
  content:"";
  position: absolute;
  top: 5px; /* move it down because of rounded corners */
  width: 20px; /* same as height */
  height: 22px; /* button_outer_height / sqrt(2) */
  background: inherit; /* use parent background */
  border: inherit; /* use parent border */
  border-left-color: transparent; /* hide left border */
  border-bottom-color: transparent; /* hide bottom border */
  border-radius: 0px 4px 0px 0px; /* round arrow corner, the shorthand property doesn't accept "inherit" so it is set to 4px */
  -webkit-border-radius: 0px 4px 0px 0px;
  -moz-border-radius: 0px 4px 0px 0px;
}

.btn-arrow-right:before,
.btn-arrow-right:after {
  transform: rotate(45deg); /* rotate right arrow squares 45 deg to point right */
  -webkit-transform: rotate(45deg);
  -moz-transform: rotate(45deg);
  -o-transform: rotate(45deg);
  -ms-transform: rotate(45deg);
}

.btn-arrow-left:before,
.btn-arrow-left:after {
  transform: rotate(225deg); /* rotate left arrow squares 225 deg to point left */
  -webkit-transform: rotate(225deg);
  -moz-transform: rotate(225deg);
  -o-transform: rotate(225deg);
  -ms-transform: rotate(225deg);
}
.btn-arrow-right:before,
.btn-arrow-left:before { /* align the "before" square to the left */
  left: -11px;
}

.btn-arrow-right:after,
.btn-arrow-left:after { /* align the "after" square to the right */
  right: -11px;
}

.btn-arrow-right:after,
.btn-arrow-left:before { /* bring arrow pointers to front */
  z-index: 1;
}

.btn-arrow-right:before,
.btn-arrow-left:after { /* hide arrow tails background */
  background-color: transparent;
}

.btn.btn-highlighted {
  border-width: 1px!important;
  border-color: Red!important;
}

//------------------------------------------------------------------------------------------------------------------------
// STATES
//------------------------------------------------------------------------------------------------------------------------

//Default
.btn.btn-default {
  background-color: $state-disabled-bg;
  color: $state-disabled-text;
}


//New
.btn.btn-New {
  background-color: $state-new-bg;
  color: $state-new-text;
}

//State = Waiting
.btn.btn-Waiting {
  background-color: $state-waiting-bg;
  color: $state-waiting-text;
}

//State = Unassigned
.btn.btn-Unassigned {
  background-color: $state-unassigned-bg;
  color: $state-unassigned-text;  
}

//State = Assigned
.btn.btn-Assigned {
  background-color: $state-assigned-bg;
  color: $state-assigned-text;
}

//State = Accepted
.btn.btn-Accepted {
  background-color: $state-accepted-bg;
  color: $state-accepted-text;
}

//State = Rejected
.btn.btn-Rejected {
  background-color: $state-rejected-bg;
  color: $state-rejected-text;
}

//State = Work in Progress
.btn.btn-Submitted,
.btn.btn-Work.in.Progress {
  background-color: $state-workinprogress-bg;
  color: $state-workinprogress-text;
}

//State = In Review
.btn.btn-Promoted, 
.btn.btn-In.Review {
  background-color: $state-inreview-bg; 
  color: $state-inreview-text;
}

//State = Rework
.btn.btn-Returned,
.btn.btn-Rework {
  background-color: $state-rework-bg;
  color: $state-rework-text;
}

//State = Close Complete
.btn.btn-Completed {
  background-color: $state-completed-bg;
  color: $state-completed-text;
}

//State = Closed Incomplete
/* 2.6.0 | 2021-04-23 | mmcc | STRY0090503 Closed Incomplete is missing the color */
/*.btn.btn-Incomplete { */
.btn.btn-Closed.Incomplete {
  background-color: $state-closedincomplete-bg;
  color: $state-closedincomplete-text;
}

//State = Close Skipped
.btn.btn-Cancelled {
  background-color: $state-cancelled-bg;
  color: $state-cancelled-text;
}

sp_widget.script:
//------------------------------------------------------------------------------------------------------------------------
// WIDGET BASE: FIELDS
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES
//
// 2.6.0 | 2021-04-23 | mmcc | STRY0090503 Closed Incomplete is missing the color in the filter widget on the Modern 
//                                         Portal page and Chevron color is missing on the task form.
//                                         Change made in CSS only.
//
// 2.7.0 | 2021-10-25 | mmcc | STRY0108211 Stretch - Task State Chevron- Remove Tool Tips  
//                                         In HTML, for the button, removed title="State: {{data.state}}".
//                                         In CSS, make chevron non-clickable and do not change the cursor on hover.
//                                         Change made in HTML and CSS.
//
//------------------------------------------------------------------------------------------------------------------------
(function(data) {
	var gr;


	if(input){
		data.table = input.table;
		data.sys_id = input.sys_id;
		gr = new GlideRecord(data.table);
		if(!gr.get(data.sys_id)){
			return;
		}
	} else {
		gr = $sp.getRecord();
		if (gr == null)
			return;
	}

	data.sys_id = gr.getUniqueValue();
	data.table = gr.getTableName();
	data.filter = 'sys_id='+data.sys_id;

	if (data.table == "x_153465_discovert_route_task_instance") {
		data.state = gr.state.getDisplayValue().toString();
		data.tasker_type = gr.tasker_type.getDisplayValue().toString();
		data.u_wait_for_subtasks_to_finish = gr.u_wait_for_subtasks_to_finish.getDisplayValue().toString();
		data.flow = createProcessFlow(data.table, data.sys_id, data.tasker_type);
	}

	// Check the process flow
	function createProcessFlow(table, id, tasker_type) {
		//var table = gr.getTableName();
		//var id = gr.getUniqueValue();

		var gf = new GlideRecord('sys_process_flow'); //Note: GlideRecordSecure is not feasible to use on this widget that is reading values from a table enable by the process flow plugin
		gf.addActiveQuery();
		gf.addQuery('table', table);
		if (data.u_wait_for_subtasks_to_finish.toString() == "false")
			gf.addQuery('label', '!=', 'Wait for subtasks');
		gf.addQuery('description', 'CONTAINS', tasker_type);
		gf.orderBy('order');
		gf.query();

		var currentStep;
		var items = [];
		while (gf.next()) {
			var item = {};
			item.name = gf.label.toString();
			item.colour = getCurrentStep(gf.condition.toString(), table, id); //OOTB
			//item.colour = gf.label.toString();
			items.push(item);

		}	

		if (gr.getTableName() == "x_153465_discovert_route_task_instance")
			currentStep =  gr.state.getDisplayValue().toString();//*
		if (gr.getTableName() == "x_153465_discovert_war_sar_reporting")
			currentStep =  gr.status.getDisplayValue().toString();

		items = retoActiveSuccess(items, currentStep);
		return items;
	}


	// Check the process flow query against the current job to see if the conditions match
	function getCurrentStep(step, table, id) {
		var gnr = new GlideRecord(table);
		gnr.addEncodedQuery(step);
		gnr.addQuery('sys_id', id);
		gnr.query();

		if (gnr.next()) {
			//return 'warning';
			//return gr.state.getDisplayValue().toString();//highlighted'; //*
			var currentStep;
			if (gr.getTableName() == "x_153465_discovert_route_task_instance")
				currentStep =  gr.state.getDisplayValue().toString();//*
			if (gr.getTableName() == "x_153465_discovert_war_sar_reporting")
				currentStep =  gr.status.getDisplayValue().toString();

			return currentStep;

		} else {
			//return 'primary';
			return 'default';
		}

	}

	// Set the previous steps in the flow to success if the current step is further down the order
	function retoActiveSuccess(items, currentStep) {
		var i = 0;
		for (var key in items) {
			var value = items[key];

			if (value.colour == currentStep) { 
			//if (value.colour == 'warning') { //OOTB
				var index = i;
				for (var j = 0; j<i; j++) {
					//items[j].colour = 'success'; //OOTB
					items[j].colour = items[j].name;
				}			
				if (index == items.length) {
					value.colour = 'sucess';
				}
				break;
			}
			i++;
		}
		return items;
	}




})(data);

//------------------------------------------------------------------------------------------------------------------------
// WIDGET BASE: FIELDS
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES
//------------------------------------------------------------------------------------------------------------------------

